# =============================================================================
# Window Layout Geometry
# =============================================================================

# Compute x y w h for a given slot given total players and screen dimensions.
# Layouts: 1p=full, 2p=top/bottom, 3-4p=2x2 grid (slot 4 empty if 3p).
compute_geometry() {
    local slot=$1 total=$2 W=$3 H=$4
    local hw=$(( W / 2 )) hh=$(( H / 2 ))
    case $total in
        1) echo "0 0 $W $H" ;;
        2) [ "$slot" -eq 1 ] && echo "0 0 $W $hh" || echo "0 $hh $W $hh" ;;
        3|4)
            case $slot in
                1) echo "0 0 $hw $hh" ;;
                2) echo "$hw 0 $hw $hh" ;;
                3) echo "0 $hh $hw $hh" ;;
                4) echo "$hw $hh $hw $hh" ;;
            esac ;;
    esac
}

